#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
const int N=1e3+1,M=201,inf=1e9+7;
int n,m,k,a[N],b[M];
int f[2][M][M][2];
string in;
signed main(void)
{
	ios::sync_with_stdio(0);
	cin>>n>>m>>k;
	cin>>in;
	FOR(i,1,n)a[i]=in[i-1]-'a'+1;
	cin>>in;
	FOR(i,1,m)b[i]=in[i-1]-'a'+1;
	f[0][0][0][0]=f[1][0][0][0]=1;
	FOR(i,1,n)
	{
		FOR(j,1,(m<i?m:i))
		{
			FOR(t,1,k)
			{
				f[i&1][j][t][0]=(f[(i-1)&1][j][t][0]+f[(i-1)&1][j][t][1])%inf;
				if(a[i]==b[j])
				{
					f[i&1][j][t][1]=(f[(i-1)&1][j-1][t][1]+f[(i-1)&1][j-1][t-1][0]+f[(i-1)&1][j-1][t-1][1])%inf;
				}
				else f[i&1][j][t][1]=0;
			}
		}
	}
	cout<<(f[n&1][m][k][0]+f[n&1][m][k][1])%inf<<"\n";
	return false;
}
